const amqp = require('amqplib');

// Configuration
const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = 'payment_events';

async function processPayment(paymentDetails) {
  // Simulate payment processing logic
  return new Promise(resolve => {
    setTimeout(() => {
      const isSuccess = Math.random() > 0.1; // 90% success rate
      if (isSuccess) {
        console.log(`[SUCCESS] Processed payment for order ${paymentDetails.orderId} with amount ${paymentDetails.amount}`);
        resolve({ status: 'success', transactionId: `TRX-${Date.now()}-${Math.random().toString(36).substr(2, 5)}` });
      } else {
        console.error(`[FAILURE] Failed to process payment for order ${paymentDetails.orderId}. Retrying might be needed.`);
        resolve({ status: 'failed', error: 'Payment gateway declined' });
      }
    }, Math.random() * 2000 + 500); // Simulate network latency and processing time
  });
}

async function startConsumer() {
  let connection;
  try {
    connection = await amqp.connect(RABBITMQ_URL);
    const channel = await connection.createChannel();

    await channel.assertQueue(QUEUE_NAME, {
      durable: true // Ensure the queue survives broker restarts
    });

    console.log(`[*] Waiting for messages in ${QUEUE_NAME}. To exit press CTRL+C`);

    channel.consume(QUEUE_NAME, async (msg) => {
      if (msg !== null) {
        try {
          const content = JSON.parse(msg.content.toString());
          console.log(`[x] Received message:`, content);

          // Execute payment logic directly
          const result = await processPayment(content);
          console.log(`[x] Payment processing result for order ${content.orderId}:`, result);

          // Acknowledge the message only after successful processing
          channel.ack(msg);
        } catch (error) {
          console.error(`[!] Error processing message:`, error);
          console.error(`[!] Message content:`, msg.content.toString());
          // Optionally, nack the message to requeue or send to dead-letter queue
          // For now, we'll just log and ack to prevent endless loop on malformed messages
          // In a real-world scenario, you might want to nack with {requeue: false} or send to a DLQ
          channel.ack(msg);
        }
      }
    }, {
      noAck: false // Important: We will manually acknowledge messages
    });

  } catch (error) {
    console.error('Failed to connect to RabbitMQ or start consumer:', error);
    if (connection) {
      try {
        await connection.close();
      } catch (closeError) {
        console.error('Error closing RabbitMQ connection:', closeError);
      }
    }
    // Attempt to restart consumer after a delay
    setTimeout(startConsumer, 5000);
  }
}

// Start the consumer
startConsumer();

// Handle graceful shutdown
process.on('SIGINT', async () => {
  console.log('Shutting down consumer...');
  // No need to explicitly close connection here if amqplib handles it on process exit,
  // but good practice for more complex applications.
  // In simple cases, process exit will close the connection.
  process.exit(0);
});